/// BTStepNumber — reusable step/page pill widget.
/// Figma: node 3007-2442.
///
/// ## Usage
/// ```dart
/// // Normal page pill
/// BTStepNumber(
///   page: 3,
///   isActive: currentPage == 3,
///   onTap: () => setState(() => currentPage = 3),
///   colors: context.btColor,
/// )
///
/// // Ellipsis placeholder
/// BTStepNumber.ellipsis(colors: context.btColor)
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:flutter/material.dart';
import 'package:flutter_svg/flutter_svg.dart';

/// A 32×32 page-pill button with five visual states:
/// Default, Hover, Active, Disabled, Ellipsis (more_horiz icon).
class BTStepNumber extends StatefulWidget {
  const BTStepNumber({
    required this.page,
    required this.colors,
    this.isActive = false,
    this.isDisabled = false,
    this.onTap,
    super.key,
  }) : _isEllipsis = false;

  /// Ellipsis / More state — shows the ⋯ icon; non-interactive.
  const BTStepNumber.ellipsis({
    required this.colors,
    super.key,
  })  : page = 0,
        isActive = false,
        isDisabled = false,
        onTap = null,
        _isEllipsis = true;

  final int page;
  final BTColorTheme colors;
  final bool isActive;
  final bool isDisabled;
  final VoidCallback? onTap;
  final bool _isEllipsis;

  @override
  State<BTStepNumber> createState() => _BTStepNumberState();
}

class _BTStepNumberState extends State<BTStepNumber> {
  bool _isHovered = false;
  bool _isPressed = false;

  bool get _isInteractive => !widget.isDisabled && !widget._isEllipsis;

  Color get _bgColor {
    if (widget._isEllipsis || widget.isDisabled) return Colors.transparent;
    if (widget.isActive || _isPressed || _isHovered) return widget.colors.bg.subtle;
    return Colors.transparent;
  }

  Color get _borderColor {
    if (widget._isEllipsis || widget.isDisabled) return Colors.transparent;
    if (widget.isActive) return BTColor.brand.primary;
    return widget.colors.border.primary;
  }

  Color get _textColor {
    if (widget.isDisabled) return widget.colors.text.disabled;
    if (widget._isEllipsis) return widget.colors.text.secondary;
    return widget.colors.text.primary;
  }

  @override
  Widget build(BuildContext context) {
    Widget content;

    if (widget._isEllipsis) {
      content = SvgPicture.asset(
        'packages/btech_assets/assets/icons/pagination/more_horiz.svg',
        width: 16.0,
        height: 16.0,
        colorFilter: ColorFilter.mode(_textColor, BlendMode.srcIn),
      );
    } else {
      content = Text(
        '${widget.page}',
        style: TextStyle(
          fontSize: 12.0,
          fontWeight: FontWeight.w500,
          color: _textColor,
        ),
      );
    }

    final pill = MouseRegion(
      cursor: _isInteractive
          ? SystemMouseCursors.click
          : SystemMouseCursors.basic,
      onEnter: _isInteractive ? (_) => setState(() => _isHovered = true) : null,
      onExit:  _isInteractive ? (_) => setState(() => _isHovered = false) : null,
      child: GestureDetector(
        onTap: _isInteractive ? widget.onTap : null,
        onTapDown:   _isInteractive ? (_) => setState(() => _isPressed = true)  : null,
        onTapUp:     _isInteractive ? (_) => setState(() => _isPressed = false) : null,
        onTapCancel: _isInteractive ? ()  => setState(() => _isPressed = false) : null,
        child: Container(
          width: 32.0,
          height: 32.0,
          decoration: BoxDecoration(
            color: _bgColor,
            border: widget._isEllipsis || widget.isDisabled
                ? null
                : Border.all(color: _borderColor),
            borderRadius: BorderRadius.circular(BTRadius.sm),
          ),
          alignment: Alignment.center,
          child: content,
        ),
      ),
    );

    if (!widget._isEllipsis && !widget.isDisabled) {
      return Semantics(
        button: true,
        label: 'Page ${widget.page}',
        selected: widget.isActive,
        child: pill,
      );
    }
    return pill;
  }
}
